function installMapPi3DevConsole(settings = {}) {
  if (typeof window === 'undefined' || window.__MAPPI3_DEV_CONSOLE__) return;
  window.__MAPPI3_DEV_CONSOLE__ = true;
  const facts = { ...mapPi3DevFacts, selectedTheme: settings.theme || 'Topo Night', loadedAt: new Date().toISOString() };
  window.MapPI3Dev = {
    facts,
    status: () => fetch('/api/status').then(r => r.json()),
    captive: () => fetch('/api/captive/status').then(r => r.json()),
    gps: () => fetch('/api/command/gps-sample', { method:'POST', headers:{'Content-Type':'application/json'}, body:'{}' }).then(r => r.json()),
    noaa: () => fetch('/api/noaa-weather', { cache:'no-store' }).then(r => r.json()),
    media: () => fetch('/api/media/library', { cache:'no-store' }).then(r => r.json()),
    help: () => facts,
  };
  const badge = 'background:#07130d;color:#b9ffd2;border:1px solid #18c56e;border-radius:8px;padding:3px 8px;font-weight:700';
  console.groupCollapsed('%c🧭 MapPI3 Trail OS developer console', badge);
  console.info('MapPI3 is a local-first trail buddy designed for a Raspberry Pi hotspot, offline maps/references, GPS/PPS, Sense HAT controls, weather/cache plugins, media library, and field AI notes.');
  console.table(facts);
  console.info('Try: MapPI3Dev.help(), MapPI3Dev.status(), MapPI3Dev.captive(), MapPI3Dev.gps(), MapPI3Dev.media() while connected to the Pi hotspot.');
  console.info('Safety note: MapPI3 assists but does not replace real navigation, emergency tools, first aid training, or local laws.');
  console.groupEnd();
}

