function loadStored(key, fallback) { try { const raw = localStorage.getItem(key); return raw ? JSON.parse(raw) : fallback; } catch { return fallback; } }
function profileHash(value) { let hash = 2166136261; String(value || '').split('').forEach(ch => { hash ^= ch.charCodeAt(0); hash = Math.imul(hash, 16777619); }); return (hash >>> 0).toString(16); }
function blankAccountState() { return { active: 'Guest', accounts: { CAK3D: { ready: false, hash: '' }, 'tiny-Z': { ready: false, hash: '' } } }; }
function newDeviceId() { return `mappi3-${Date.now()}-${Math.random().toString(16).slice(2)}`; }
function guestResetKeys() { return ['mappi3.selectedRouteId','mappi3.searchQuery','mappi3.elapsed','mappi3.progress','mappi3.hiker','mappi3.completedTrails','mappi3.healthHistory','mappi3.customWaypointsByRoute','mappi3.walk','mappi3.walkHistory','mappi3.launchChecklist','mappi3.launchPlan','mappi3.readinessLog']; }
function formatClock(seconds) { const h = Math.floor(seconds / 3600), m = Math.floor((seconds % 3600) / 60), s = seconds % 60; return h ? `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}` : `${m}:${String(s).padStart(2, '0')}`; }
function yearsOld(dateString) { const birth = new Date(dateString); if (Number.isNaN(birth.getTime())) return 0; const now = new Date(); let age = now.getFullYear() - birth.getFullYear(); return (now.getMonth() < birth.getMonth() || (now.getMonth() === birth.getMonth() && now.getDate() < birth.getDate())) ? age - 1 : age; }
function foodCalories(hiker) { return (hiker.foods || []).reduce((sum, item) => sum + Number(item[1] || 0), 0); }
function calcHealth({ hiker, conditions, elapsed, progress, distanceMiles = primaryRoutePack.distanceMiles, elevationGainFt = primaryRoutePack.elevationGainFt }) {
  const hours = Math.max(elapsed / 3600, 1 / 60); const miles = progress * distanceMiles; const weightKg = Number(hiker.weightLb || 0) * 0.453592; const paceMph = miles / hours;
  const gradeLoad = elevationGainFt / Math.max(distanceMiles * 5280, 1); const heatFactor = Number(conditions.tempF) >= 80 ? 1.08 : Number(conditions.tempF) <= 40 ? 1.05 : 1; const humidityFactor = Number(conditions.humidity) >= 70 ? 1.05 : 1; const altitudeFactor = Number(conditions.elevationFt) >= 5000 ? 1.06 : 1;
  const met = Math.max(3.0, Math.min(9.5, 2.8 + paceMph * 0.9)) * (1 + Math.min(0.28, gradeLoad * 10)) * heatFactor * humidityFactor * altitudeFactor;
  const caloriesBurned = met * weightKg * hours; const normalWalkCalories = 3.5 * weightKg * hours; const pulseBpm = Number(hiker.pulseSeconds) > 0 ? Math.round((Number(hiker.pulseCount || 0) / Number(hiker.pulseSeconds)) * 60) : 0;
  const netCalories = foodCalories(hiker) - caloriesBurned; const waterTargetOz = Math.max(12, hours * (18 + (Number(conditions.tempF) > 75 ? 8 : 0) + (Number(conditions.humidity) > 65 ? 4 : 0))); const waterBalance = Number(hiker.waterOz || 0) - waterTargetOz; const effortScore = Math.round(Math.min(100, (caloriesBurned / Math.max(normalWalkCalories, 1)) * 45 + progress * 35 + (Number(hiker.heartRate || pulseBpm) > 130 ? 10 : 0)));
  return { hours, miles, paceMph, met, caloriesBurned, normalWalkCalories, pulseBpm, netCalories, waterTargetOz, waterBalance, effortScore };
}
function toRadians(deg) { return deg * Math.PI / 180; }
function distanceBetweenMiles(a, b) { if (!a || !b) return 0; const earthMiles = 3958.8; const dLat = toRadians(b.lat - a.lat); const dLon = toRadians(b.lon - a.lon); const lat1 = toRadians(a.lat); const lat2 = toRadians(b.lat); const h = Math.sin(dLat / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLon / 2) ** 2; return 2 * earthMiles * Math.asin(Math.min(1, Math.sqrt(h))); }
function traceDistanceMiles(trace = []) { return trace.reduce((sum, point, index) => sum + (index ? distanceBetweenMiles(trace[index - 1], point) : 0), 0); }
function routeLatLon(route) { return route?.geometry?.coordinates?.map(([lon, lat]) => ({ lat, lon })) || []; }
function routePointAt(route, ratio) { const points = routeLatLon(route); if (!points.length) return localHome; const index = Math.min(points.length - 1, Math.max(0, Math.round(ratio * (points.length - 1)))); return points[index]; }
function routeStatusForPoint(route, point, navWaypoints = null) { const points = routeLatLon(route); const waypointSeed = navWaypoints || route?.waypoints || []; if (!points.length || !point) return { progress: 0, offRouteFeet: 0, milesIn: 0, milesRemaining: Number(route?.distanceMiles || 0), nextWaypoint: waypointSeed[0], snappedPoint: point }; if (points.length === 1) { const miles = distanceBetweenMiles(point, points[0]); return { progress: 0, offRouteFeet: Math.round(miles * 5280), milesIn: 0, milesRemaining: Number(route.distanceMiles || 0), nextWaypoint: waypointSeed[0], snappedPoint: points[0] }; } const lat0 = toRadians(point.lat); const milesPerLat = 69; const milesPerLon = Math.cos(lat0) * 69.172; let best = { segment: 0, t: 0, miles: Infinity, snappedPoint: points[0] }; points.slice(0, -1).forEach((a, index) => { const b = points[index + 1]; const ax = (a.lon - point.lon) * milesPerLon, ay = (a.lat - point.lat) * milesPerLat; const bx = (b.lon - point.lon) * milesPerLon, by = (b.lat - point.lat) * milesPerLat; const vx = bx - ax, vy = by - ay; const len2 = vx * vx + vy * vy || 1; const t = Math.max(0, Math.min(1, -(ax * vx + ay * vy) / len2)); const sx = ax + vx * t, sy = ay + vy * t; const miles = Math.sqrt(sx * sx + sy * sy); if (miles < best.miles) best = { segment: index, t, miles, snappedPoint: { lat: a.lat + (b.lat - a.lat) * t, lon: a.lon + (b.lon - a.lon) * t } }; }); const progress = (best.segment + best.t) / (points.length - 1); const milesIn = progress * Number(route.distanceMiles || 0); const waypointList = [...waypointSeed].sort((a, b) => Number(a.mile || 0) - Number(b.mile || 0)); const nextWaypoint = waypointList.find(w => Number(w.mile) > milesIn) || waypointList.at(-1); return { progress, offRouteFeet: Math.round(best.miles * 5280), milesIn, milesRemaining: Math.max(0, Number(route.distanceMiles || 0) - milesIn), nextWaypoint, snappedPoint: best.snappedPoint }; }
