  const deleteRoutePack = (id) => { setRoutes(rs => rs.filter(route => route.id !== id || !route.custom)); setCustomWaypointsByRoute(all => { const next = { ...all }; delete next[id]; delete next[ownerRouteKey(activeOwner, id)]; return next; }); if (selectedRouteId === id) setSelectedRouteId(defaultRouteId); setGpxStatus('Deleted local custom route pack.'); };
  const onDriveTo = (route) => { const dest = driveDestinationFromRoute(route || selectedRoute); setDriveDestination(dest); if (route?.id) setSelectedRouteId(route.id); setActiveTab('Drive'); setGpxStatus(`Drive GPS opened for ${dest.label}.`); }; const onDownload = (id) => setRoutes(rs => rs.map(route => route.id === id ? { ...route, status: 'Downloaded', offlineSavedAt: Date.now(), offlineStaleAfterDays: 14, tags: Array.from(new Set([...(route.tags || []), 'downloaded'])) } : route)); const deleteOfflinePack = (id) => setRoutes(rs => rs.map(route => route.id === id ? { ...route, status: route.custom ? 'Downloaded' : 'Ready', offlineSavedAt: null, tags: (route.tags || []).filter(t => t !== 'downloaded') } : route)); const refreshOfflinePack = (id) => onDownload(id); const onStartRoute = (route) => { setSelectedRouteId(route.id); setProgress(0); setElapsed(0); setRecording(false); setActiveTab('Navigate'); setGpxStatus(`Selected ${route.name}. Opened Navigate without starting recording.`); }; const resetTrack = () => { setRecording(false); setElapsed(0); setProgress(0); };
