   const createAlternateRoute = () => { const route = planRouteVariant(selectedRoute); route.uploadedBy = activeOwner; setRoutes(rs => [route, ...rs]); setCustomWaypointsByRoute(all => ({ ...all, [ownerRouteKey(activeOwner, route.id)]: (route.customWaypoints || route.waypoints || []).map(p => ({ ...p, custom: true, editable: true })) })); setSelectedRouteId(route.id); setActiveTab('Plan'); setGpxStatus(`Created alternate route plan from ${selectedRoute.name}. Refine waypoints and save/publish when ready.`); }; const publishPublicRoute = async (note = '') => { const now = Date.now(); const publicRoute = { ...selectedRoute, id: selectedRoute.custom ? selectedRoute.id : `public-${now}`, custom: true, publicCreated: true, catalogCategory: 'Public created', uploadedBy: activeOwner, uploadedAt: now, publicNote: note || 'Custom route/marker plan shared from MapPI3.', tags: Array.from(new Set([...(selectedRoute.tags || []), 'public-created', 'shared'])), status: 'Downloaded', customWaypoints }; setRoutes(rs => [publicRoute, ...rs.filter(r => r.id !== publicRoute.id)]); setSelectedRouteId(publicRoute.id); try { if (supabaseConfig.enabled) await saveCloudRecord('public_route_pack', publicRoute); setGpxStatus(`Published public-created route locally${supabaseConfig.enabled ? ' and to Supabase' : ''}: ${publicRoute.name}.`); } catch (err) { setGpxStatus(`Public route saved locally; cloud publish failed: ${err.message}`); } }; const onExportGpx = () => { downloadTextFile('mappi3-selected-route.gpx', makeGpx(selectedRoute), 'application/gpx+xml'); setGpxStatus(`Exported mappi3-selected-route.gpx from ${selectedRoute.name}.`); }; const onExportRouteGpx = (route) => downloadTextFile(`${(route.name || 'mappi3-route').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeRouteGpx(route), 'application/gpx+xml'); const onExportWalkGpx = (item) => downloadTextFile(`${(item.name || 'mappi3-walk').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeWalkGpx(item), 'application/gpx+xml'); co